import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSVulnerableServlet extends HttpServlet {
    public void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        // Vulnerability: Displaying user input directly on the web page without proper sanitization
        out.println("<html>");
        out.println("<head><title>XSS Vulnerable Page</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome!</h1>");
        out.println("<p>You entered: " + userInput + "</p>"); // User input displayed without sanitization
        out.println("</body>");
        out.println("</html>");
    }
}

