import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

public class XSSSafeServlet extends HttpServlet {
    private final PolicyFactory policy = Sanitizers.FORMATTING.and(Sanitizers.BLOCKS);

    public void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>XSS Safe Page</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome!</h1>");
        out.println("<p>You entered: " + policy.sanitize(userInput) + "</p>"); // Sanitize

